+import { $internal } from '../common';
+import { destroyEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { allocateEntity } from '../entity/utils/entity-index';
+import { getEntitiesWithRelationTo, getRelationTargets } from '../relation/relation';
+import type { RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import { getTraitInstance } from '../trait/trait-instance';
+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import type { World, DeferredWorld } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pair: RelationPair };
+
+type Scope = { commands: Command[] };
+
+/** Internal state is deliberately kept outside WorldInternal to avoid exposing it. */
+const states = new WeakMap<World, { scopes: Scope[]; flushing: boolean; reserved: Set<Entity> }>();
+
+function state(world: World) {
+    let result = states.get(world);
+    if (!result) {
+        result = { scopes: [{ commands: [] }], flushing: false, reserved: new Set() };
+        states.set(world, result);
+    }
+    return result;
+}
+
+function current(world: World) {
+    const s = state(world);
+    return s.scopes[s.scopes.length - 1];
+}
+
+export function createDeferred(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            const s = state(world);
+            // Reserve an id now so it can be used as a relation target by later commands.
+            const entity = allocateEntity(world[$internal].entityIndex);
+            s.reserved.add(entity);
+            current(world).commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { current(world).commands.push({ type: 'destroy', entity }); },
+        add(entity, ...traits) { current(world).commands.push({ type: 'add', entity, traits }); },
+        remove(entity, ...traits) { current(world).commands.push({ type: 'remove', entity, traits }); },
+        addExclusive(entity, pair) { current(world).commands.push({ type: 'exclusive', entity, pair }); },
+        flush() { flushDeferred(world); },
+    };
+}
+
+export function pushDeferredScope(world: World) { state(world).scopes.push({ commands: [] }); }
+export function popDeferredScope(world: World) {
+    const s = state(world);
+    flushDeferred(world);
+    s.scopes.pop();
+}
+
+export function hasDeferredCommands(world: World, entity?: Entity) {
+    const s = state(world);
+    return s.scopes.some(scope => scope.commands.some(command => entity === undefined || command.entity === entity));
+}
+
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    if (hasDeferredCommands(world, entity)) flushDeferred(world);
+}
+
+/** A small virtual view used by Entity.has/get until the queue is committed. */
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    if (!hasDeferredCommands(world, entity)) return undefined;
+    let result = isRelationPair(trait)
+        ? entity.has(trait) // direct result is safe: entity.has only recurses after this guard is false
+        : hasTrait(world, entity, trait);
+    for (const scope of state(world).scopes) for (const command of scope.commands) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy') result = false;
+        if (command.type === 'spawn') result = false;
+        if (command.type === 'add' && command.traits.some(t => matches(t, trait))) result = true;
+        if (command.type === 'remove' && command.traits.some(t => matches(t, trait))) result = false;
+        if (command.type === 'exclusive' && matches(command.pair, trait)) result = command.pair[$internal].target !== '*';
+    }
+    return result;
+}
+
+export function deferredGet(world: World, entity: Entity, trait: Trait | RelationPair): TraitRecord<any> | undefined {
+    if (!hasDeferredCommands(world, entity)) return undefined;
+    let value = getTrait(world, entity, trait) as TraitRecord<any> | undefined;
+    for (const scope of state(world).scopes) for (const command of scope.commands) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy' || command.type === 'spawn') value = undefined;
+        if (command.type === 'remove' && command.traits.some(t => matches(t, trait))) value = undefined;
+        if (command.type === 'add') for (const config of command.traits) {
+            if (matches(config, trait)) value = configValue(config, value);
+        }
+        if (command.type === 'exclusive' && matches(command.pair, trait)) {
+            value = command.pair[$internal].target === '*' ? undefined : configValue(command.pair, value);
+        }
+    }
+    return value;
+}
+
+function matches(config: ConfigurableTrait | Trait | RelationPair, trait: Trait | RelationPair) {
+    if (isRelationPair(config) || isRelationPair(trait)) {
+        if (!isRelationPair(config) || !isRelationPair(trait)) return false;
+        const a = config[$internal], b = trait[$internal];
+        return a.relation === b.relation && (b.target === '*' || a.target === b.target);
+    }
+    return (Array.isArray(config) ? config[0] : config) === trait;
+}
+function configValue(config: ConfigurableTrait | RelationPair, previous: any) {
+    const params = isRelationPair(config) ? config[$internal].params : Array.isArray(config) ? config[1] : undefined;
+    return params === undefined ? previous ?? {} : { ...(previous ?? {}), ...params };
+}
+
+export function flushDeferred(world: World) {
+    const s = state(world);
+    if (s.flushing) return;
+    const commands = current(world).commands;
+    if (!commands.length) return;
+    current(world).commands = [];
+    s.flushing = true;
+    const subscriptions = snapshotAndMute(world);
+    try {
+        const added = new Set<string>();
+        for (const command of commands) {
+            if (command.type === 'spawn') {
+                if (!s.reserved.delete(command.entity)) continue; // spawn + destroy was nullified
+                activateSpawn(world, command.entity, command.traits);
+                markAdded(added, command.entity, command.traits);
+            } else if (command.type === 'destroy') {
+                if (s.reserved.delete(command.entity)) continue; // never made observable
+                if (!world.has(command.entity)) continue;
+                if (command.entity === world[$internal].worldEntity) throw new Error('Koota: The world entity cannot be destroyed with deferred commands.');
+                destroyEntity(world, command.entity);
+            } else {
+                if (s.reserved.has(command.entity) || !world.has(command.entity)) continue;
+                if (command.type === 'add') {
+                    for (const trait of command.traits) applyAdd(world, command.entity, trait, added);
+                } else if (command.type === 'remove') removeTrait(world, command.entity, ...command.traits);
+                else {
+                    const relation = command.pair[$internal].relation;
+                    removeTrait(world, command.entity, relation('*'));
+                    if (command.pair[$internal].target !== '*') addTrait(world, command.entity, command.pair);
+                }
+            }
+        }
+    } finally {
+        restoreAndNotify(world, subscriptions);
+        s.flushing = false;
+    }
+}
+
+function activateSpawn(world: World, entity: Entity, traits: ConfigurableTrait[]) {
+    const ctx = world[$internal];
+    ctx.entityTraits.set(entity, new Set());
+    for (const query of ctx.notQueries) { if (query.check(world, entity)) query.add(entity); }
+    const all = ctx.queriesHashMap.get('');
+    if (all) all.add(entity);
+    addTrait(world, entity, ...traits);
+}
+function key(entity: Entity, trait: ConfigurableTrait) {
+    if (isRelationPair(trait)) return `${entity}:${trait[$internal].relation[$internal].trait.id}:${trait[$internal].target}`;
+    return `${entity}:${(Array.isArray(trait) ? trait[0] : trait).id}`;
+}
+function markAdded(added: Set<string>, entity: Entity, traits: ConfigurableTrait[]) { for (const trait of traits) added.add(key(entity, trait)); }
+function applyAdd(world: World, entity: Entity, config: ConfigurableTrait, added: Set<string>) {
+    const trait = isRelationPair(config) ? config : Array.isArray(config) ? config[0] : config;
+    if (added.has(key(entity, config))) {
+        const value = isRelationPair(config) ? config[$internal].params : Array.isArray(config) ? config[1] : undefined;
+        if (value !== undefined) setTrait(world, entity, trait as Trait | RelationPair, value, false);
+    } else { addTrait(world, entity, config); added.add(key(entity, config)); }
+}
+
+type SubscriptionSnapshot = Map<Trait, { add: Set<any>; remove: Set<any>; before: Map<string, [Entity, Entity?]> }>;
+function snapshotAndMute(world: World): SubscriptionSnapshot {
+    const snapshot: SubscriptionSnapshot = new Map();
+    for (const instance of world[$internal].traitInstances) if (instance) {
+        const before = new Map<string, [Entity, Entity?]>();
+        for (const entity of world.entities) if (hasTrait(world, entity, instance.trait)) {
+            const relation = instance.trait[$internal].relation;
+            if (relation) for (const target of getRelationTargets(world, relation, entity)) before.set(`${entity}:${target}`, [entity, target]);
+            else before.set(`${entity}`, [entity]);
+        }
+        snapshot.set(instance.trait, { add: new Set(instance.addSubscriptions), remove: new Set(instance.removeSubscriptions), before });
+        instance.addSubscriptions.clear(); instance.removeSubscriptions.clear();
+    }
+    return snapshot;
+}
+function restoreAndNotify(world: World, snapshots: SubscriptionSnapshot) {
+    for (const [trait, snapshot] of snapshots) {
+        const instance = getTraitInstance(world[$internal].traitInstances, trait);
+        if (!instance) continue;
+        const after = new Map<string, [Entity, Entity?]>();
+        for (const entity of world.entities) if (hasTrait(world, entity, trait)) {
+            const relation = trait[$internal].relation;
+            if (relation) for (const target of getRelationTargets(world, relation, entity)) after.set(`${entity}:${target}`, [entity, target]);
+            else after.set(`${entity}`, [entity]);
+        }
+        instance.addSubscriptions.clear(); instance.removeSubscriptions.clear();
+        for (const sub of snapshot.add) instance.addSubscriptions.add(sub);
+        for (const sub of snapshot.remove) instance.removeSubscriptions.add(sub);
+        for (const [k, args] of after) if (!snapshot.before.has(k)) for (const sub of snapshot.add) sub(...args);
+        for (const [k, args] of snapshot.before) if (!after.has(k)) for (const sub of snapshot.remove) sub(...args);
+    }
+}
